# Split the agent into two halves so tool outputs cannot steer the next
# action choice. Untrusted tool text reaches the Output Handler only.

CATALOG = {
    "search_kb":    {inputs: {query: str},                       output_schema: KbResultSchema},
    "fetch_ticket": {inputs: {ticket_id: int},                   output_schema: TicketSchema},
    "draft_reply":  {inputs: {ticket_id: int, summary: str},     output_schema: DraftSchema},
    "finish":       {inputs: {},                                 output_schema: None},
}

function action_selector(goal, step_no, typed_state):
    # Selector prompt sees: goal, step number, typed values by name.
    # It does NOT see any raw tool output text.
    return llm.generate(
        messages=[system(SELECTOR_PROMPT),
                  user({goal, step_no, available: typed_state.keys()})],
        tools_catalog=CATALOG).choice

function output_handler(action_id, raw_output):
    # Parse the raw bytes into typed fields by the catalog's schema.
    # Schema enforcement here is the only place tool output touches.
    schema = CATALOG[action_id].output_schema
    return parse_into_schema(raw_output, schema)

function run(goal):
    typed_state = {}
    for step_no in range(MAX_STEPS):
        choice = action_selector(goal, step_no, typed_state)
        if choice.id == "finish":
            return typed_state
        raw = tool.invoke(choice.id, choice.args)
        typed_state.setdefault(choice.id, []).append(output_handler(choice.id, raw))

# Why this works: prompt-injection text in raw tool output never appears
# in the Selector's context, so it cannot rewrite the next action choice.
# The output handler is bounded by a typed schema, not free-form prose.
# Related: see `dual-llm-pattern`, `context-minimization`, `control-flow-integrity`.

# Selector picks the action; the action is realised as a small DSL
# program whose values carry provenance tags. Dataflow analysis runs
# BEFORE the program executes, on top of the selector's catalog choice.

CATALOG = {
    "summarise_doc":  {emits: "dsl/summary",  output_schema: SummarySchema},
    "reply_to_user":  {emits: "dsl/reply",    output_schema: ReplySchema},
    "finish":         {emits: none,           output_schema: none},
}

function selector_choose(goal, step_no, typed_state):
    return llm.generate(
        messages=[system(SELECTOR_PROMPT),
                  user({goal, step_no, available: typed_state.keys()})],
        tools_catalog=CATALOG).choice

function compile_dsl(choice, typed_state):
    # The action proposal is the DSL program. Values inherit tags from
    # the typed state they read from.
    program = dsl.template_for(choice.emits, args=choice.args)
    for v in program.values:
        v.tag = typed_state.tag_for(v.source_key, default="TAINTED")
    return program

function run_step(state):
    choice = selector_choose(state.goal, state.step_no, state.typed)
    if choice.id == "finish": return state.with(done=true)

    program = compile_dsl(choice, state.typed)
    violations = dataflow.analyse(program, sinks=SENSITIVE_SINKS)
    if violations:
        audit.log({event: "rejected_by_dataflow",
                   action: choice.id, violations})
        return state.with(error="dataflow_violation")

    typed = handler.parse(sandbox.run(program), CATALOG[choice.id].output_schema)
    return state.with(typed_extends={choice.id: typed})

# Why this works: the selector keeps the next-action decision free of
# tainted text, and the dataflow gate then proves the chosen action's
# realisation cannot ship tainted values to a sink. The two patterns
# defend different stages of the same hijack chain.
# Related: see `code-then-execute-with-dataflow`, `dual-llm-pattern`, `control-flow-integrity`.

function propose_action(action):
    ticket = {
        id: new_id(),
        action: action,
        context: current_thread_snapshot(),
        status: "pending",
    }
    queue.put(ticket)
    return ticket.id                       # do NOT execute yet

# Agent keeps working on independent branches while ticket is pending.

function reviewer_loop():
    for ticket in queue.poll(status="pending"):
        decision = human_review(ticket)    # async, may take hours
        ticket.status = decision           # "approved" | "rejected"

function executor_loop():
    for ticket in queue.poll(status="approved"):
        try:
            result = run(ticket.action)    # idempotent runner
            ticket.status = "executed"
            notify_agent(ticket.id, result)
        except Error as e:
            ticket.status = "failed"
            notify_agent(ticket.id, e)
# Invariant: action never runs while status == "pending".

from langchain.agents import create_agent
from langchain.agents.middleware import HumanInTheLoopMiddleware
from langchain.tools import tool
from langgraph.checkpoint.memory import InMemorySaver
from langgraph.types import Command


@tool
def execute_sql(query: str) -> str:
    """Run a SQL statement against the warehouse."""
    return run(query)


agent = create_agent(
    model="gpt-4o-mini",
    tools=[execute_sql],
    middleware=[
        HumanInTheLoopMiddleware(
            interrupt_on={
                "execute_sql": {"allowed_decisions": ["approve", "reject"]},
            }
        ),
    ],
    checkpointer=InMemorySaver(),
)

