# Control surface is a REST API; snapshots include enough state to
# rehydrate (including provider context ids). Resume validates that
# the charter and tool catalog haven't drifted since pause.

function api_pause(run_id, actor):
    control_store.set(run_id, "pause")
    audit.log({event: "runtime.pause", run_id, actor})
    return http(202, {ok: true, run_id})

function api_cancel(run_id, actor):
    control_store.set(run_id, "cancel")
    audit.log({event: "runtime.cancel", run_id, actor})
    return http(202, {ok: true, run_id})

function api_resume(run_id, actor):
    snap = snap_store.get(run_id)
    if snap is none: return http(404)
    if snap.charter_version != current_charter_version():
        audit.log({event: "runtime.resume.refused",
                   reason: "charter_drift", run_id})
        return http(409, {error: "CHARTER_DRIFT_SINCE_PAUSE",
                          snapshot_version: snap.charter_version,
                          current_version:  current_charter_version()})
    if snap.tool_catalog_hash != current_catalog_hash():
        return http(409, {error: "CATALOG_DRIFT_SINCE_PAUSE"})
    control_store.set(run_id, "running")
    audit.log({event: "runtime.resume", run_id, actor})
    return http(202)

function snapshot(state):
    snap_store.put(state.run_id, {
        history:           state.history,
        in_flight:         state.in_flight,
        provider_ctx_id:   state.provider_ctx_id,
        charter_version:   current_charter_version(),
        tool_catalog_hash: current_catalog_hash(),
        step_no:           state.step_no,
    })

function run(state):
    while not state.done:
        snapshot(state)
        match control_store.get(state.run_id):
            case "pause":
                control_store.wait_change(state.run_id)
            case "cancel":
                for undo in reversed(state.in_flight):
                    try: undo()
                    except Error as e: audit.log("compensator_failed", e)
                ui.show("cancelled"); return
            case "running":
                state = step(state)

# Why this works: pause/resume across config drift would silently change
# the agent's behaviour mid-run. Refusing resume on drift forces the
# operator to choose: start a fresh run or accept the new version.
# Related: see `agent-resumption`, `durable-workflow-snapshot`, `kill-switch`.

# The runtime treats cancel as one termination leaf among many. Pause
# is a separate state that suspends leaf evaluation entirely. One
# uniform composite drives all stops.

class CancelSignalLeaf:
    function is_terminated(s):
        if control_store.get(s.run_id) == "cancel":
            return (true, "user_cancel")
        return (false, none)

class StepBudgetLeaf:
    function is_terminated(s):
        return (s.step_no >= self.max, "step_budget") if s.step_no >= self.max \
               else (false, none)

TERMINATION = Any([
    CancelSignalLeaf(),
    StepBudgetLeaf(max=200),
    NoProgressLeaf(window=5),
])

function step(state):
    snap_store.put(state.run_id, snapshot(state))    # durable each step
    reply = llm.generate(messages=state.history, tools=TOOLS)
    for call in reply.tool_calls:
        state.in_flight.append(call.compensator)
        result = tool.invoke(call.name, call.args)
        state.history.append(tool_result(call.id, result))
        state.in_flight.pop()
    return state

function run(state):
    while true:
        # Pause is suspension; termination evaluation is skipped while paused.
        while control_store.get(state.run_id) == "pause":
            control_store.wait_change(state.run_id, timeout=60)

        tripped, reason = TERMINATION.is_terminated(state)
        if tripped:
            if reason == "user_cancel":
                for undo in reversed(state.in_flight):
                    try: undo()
                    except Error as e: audit.log("compensator_failed", e)
            audit.log({event: "terminated", run_id: state.run_id, reason})
            return state
        state = step(state)

# Why this works: cancel and budget and stagnation all share one
# composite evaluator, so adding a new stop reason needs no loop edits.
# Pause stays separate because it's suspension, not termination.
# Related: see `composable-termination-conditions`, `durable-workflow-snapshot`, `compensating-action`.

REVOKE_STORE = signed_kv()                  # tamper-evident, append-only

function check_alive(agent_id):
    tok = REVOKE_STORE.get(agent_id)
    if tok and tok.kind == "revoked":
        raise Killed(reason=tok.reason)

function step(state):
    check_alive(state.agent_id)                # before every model call
    reply = llm.generate(messages=state.history, tools=TOOLS)
    for call in reply.tool_calls:
        check_alive(state.agent_id)            # ... and every tool call
        state.compensators.append(call.compensator)
        result = TOOLS[call.name].run(call.args)
        state.history.append(tool_result(call.id, result))
    return reply

function run(state):
    try:
        loop_until_done(step, state)
    except Killed as k:
        for undo in reversed(state.compensators):
            try: undo()
            except Error as e: log("compensator failed", e)
        emit("killed", k.reason)

# Kill-switch is a service, not a flag. Tokens are signed; agents are
# forced down to OS-level kill if they don't comply within the grace
# window. Re-arming requires two-operator sign-off.

KS_ENDPOINT  = "https://killswitch.internal/v1"
GRACE_S      = 30

function kill(agent_id, reason, operator):
    token = ks_client.sign_revoke(KS_ENDPOINT, agent_id, reason, operator)
    revoke_store.put(agent_id, token)
    metrics.inc("killswitch.issued")
    audit.log({event: "killswitch.issued", agent_id, reason, operator})
    schedule_after(GRACE_S, lambda: os_level_kill(agent_id))

function os_level_kill(agent_id):
    if revoke_store.get(agent_id).kind == "revoked":
        # Agent didn't honour soft revoke in grace window.
        audit.log({event: "killswitch.os_kill", agent_id})
        process_table.kill(agent_id, signal="SIGTERM")

function check_alive(agent_id):
    tok = revoke_store.get(agent_id)
    if tok and tok.kind == "revoked":
        if not ks_client.verify(tok): halt("INVALID_REVOKE_TOKEN")
        raise Killed(reason=tok.reason)

function step(state):
    check_alive(state.agent_id)
    reply = llm.generate(messages=state.history, tools=TOOLS)
    for call in reply.tool_calls:
        check_alive(state.agent_id)
        state.compensators.append(call.compensator)
        result = TOOLS[call.name].run(call.args)
        state.history.append(tool_result(call.id, result))
    return reply

function run(state):
    try: loop_until_done(step, state)
    except Killed as k:
        for undo in reversed(state.compensators):
            try: undo()
            except Error as e:
                audit.log({event: "compensator.fail", error: str(e)})
        emit("killed", k.reason)

function rearm(agent_id, op1, op2):
    if op1 == op2: return refused("REQUIRES_TWO_DIFFERENT_OPERATORS")
    revoke_store.clear(agent_id)
    audit.log({event: "killswitch.rearm", agent_id, op1, op2})

# Why this works: a soft revoke that the agent honours is the normal
# path; OS-level kill is the cliff if compliance fails. Two-operator
# re-arm prevents single-operator mistakes from putting a dangerous
# agent back online.
# Related: see `stop-hook`, `compensating-action`, `circuit-breaker`.

# Kill is not just 'stop the loop' -- it's 'stop the loop AND unwind
# what was started'. The two patterns must compose for kill to be safe.

REVOKE_STORE = signed_kv()

function check_alive(agent_id):
    tok = REVOKE_STORE.get(agent_id)
    if tok and tok.kind == "revoked":
        raise Killed(reason=tok.reason)

function step(state):
    check_alive(state.agent_id)
    reply = llm.generate(messages=state.history, tools=TOOLS)
    for call in reply.tool_calls:
        check_alive(state.agent_id)
        # Register compensator BEFORE invoking, so a kill mid-call still
        # knows the compensator exists.
        state.compensators.append({step_id: call.id,
                                   undo: call.compensator,
                                   committed: false})
        try:
            result = TOOLS[call.name].run(call.args)
            state.compensators[-1].committed = true
            state.history.append(tool_result(call.id, result))
        except Killed:
            # Re-raise; the run() handler will walk compensators.
            raise

function run(state):
    try:
        loop_until_done(step, state)
    except Killed as k:
        audit.log({event: "killed", reason: k.reason,
                   compensators: len(state.compensators)})
        for c in reversed(state.compensators):
            if not c.committed:
                # In-flight at kill time; compensator might be partial.
                audit.log({event: "compensator.in_flight", step: c.step_id})
            try: c.undo()
            except Error as e:
                audit.log({event: "compensator.fail",
                           step: c.step_id, error: str(e)})
        emit("killed_and_compensated", k.reason)

# Why this works: kill alone leaves the world in a partial state;
# compensators alone require the agent to be alive to run them. Composing
# them via run()'s try/except guarantees that even an emergency kill
# attempts to walk the world back.
# Related: see `compensating-action`, `interruptible-agent-execution`, `stop-hook`.

CAPS = {"private_data", "untrusted_content", "outbound"}

# Each tool / data-source declares its capability set.
TOOL_CAPS = {
    "read_inbox":     {"private_data"},
    "fetch_url":      {"untrusted_content"},
    "send_email":     {"outbound"},
    "render_to_user": {"outbound"},                  # browser → exfil path
}

function check_path(plan):
    used = union(TOOL_CAPS[t] for t in plan.tools)
    if CAPS.issubset(used):
        raise LethalTrifecta(used, plan)

function dispatch(plan):
