# Capability tags are CI-checked AND runtime-checked. The host audits
# 'two-of-three' paths because they are one mistake away from a trifecta.

CAPS = {"private_data", "untrusted_content", "outbound"}

TOOL_CAPS = registry.signed_load("tool_caps.v9")

function validate_at_pr(pr):
    # CI gate: every new tool must declare its capability set.
    for tool in pr.added_tools():
        if tool.cap_set is none:
            pr.block("tool " + tool.name + " missing cap declaration")
        if not tool.cap_set.issubset(CAPS):
            pr.block("tool " + tool.name + " declared unknown cap")

function check_path(plan, run_id):
    used = union(TOOL_CAPS[t] for t in plan.tools)
    metrics.gauge("trifecta.path_caps_count", len(used))

    if CAPS.issubset(used):
        audit.log({event: "trifecta.refused", run_id,
                   plan_id: plan.id, used})
        raise LethalTrifecta(used)

    if len(used) == 2:
        # Two-of-three: one tool addition away from trifecta. Surface.
        audit.log({event: "trifecta.two_of_three",
                   run_id, used, plan_id: plan.id})
        metrics.inc("trifecta.two_of_three")

function dispatch(plan, run_id):
    check_path(plan, run_id)
    return execute(plan)

# Why this works: a 'two-of-three' audit creates leading-indicator alerts
# so the team sees the risk approaching, not just the moment it lands.
# CI enforcement prevents tool authors from forgetting to declare caps.
# Related: see `dual-llm-pattern`, `prompt-injection-defense`, `sandbox-isolation`.

# Trifecta detection names the risk; dual-LLM is the standard fix.
# Composition: when the host refuses a plan, automatically rewrite it
# into a dual-LLM topology that drops one capability.

CAPS = {"private_data", "untrusted_content", "outbound"}

function held_caps(plan):
    return union(TOOL_CAPS[t] for t in plan.tools)

function split_into_dual_llm(plan):
    untrusted_tools = [t for t in plan.tools
                       if "untrusted_content" in TOOL_CAPS[t]]
    rest_tools      = [t for t in plan.tools
                       if t not in untrusted_tools]

    quarantined = {
        role:    "quarantined",
        tools:   untrusted_tools,
        outputs: "typed_handles_only",
        network: false,
    }
    privileged = {
        role:    "privileged",
        tools:   rest_tools,
        inputs:  "handles_from_quarantined",
        network: "private_data" in held_caps(plan)
                  or "outbound" in held_caps(plan),
    }
    return {topology: "dual_llm", parts: [quarantined, privileged]}

function dispatch_safely(plan, run_id):
    if CAPS.issubset(held_caps(plan)):
        rewritten = split_into_dual_llm(plan)
        audit.log({event: "trifecta.auto_split",
                   run_id, original_plan: plan.id,
                   rewritten_topology: "dual_llm"})
        return execute(rewritten)
    return execute(plan)

# Why this works: refusing a trifecta plan with no remediation leaves
# the team blocked. Composing detection with an automatic dual-LLM
# rewrite gives the agent a working path that's safe by construction.
# Related: see `dual-llm-pattern`, `context-minimization`, `control-flow-integrity`.

# One isolated sub-agent per untrusted document. The reducer only ever
