    party_name: str(max_len=120),
    amount:     decimal,
    due_date:   date,
}

function process_one(document):
    # Fresh context: only this single document and the task instructions.
    # No shared memory, no cross-document tool calls, no outbound network.
    sub_state = new_state(
        messages=[system(EXTRACT_PROMPT), user(document.bytes)],
        tools=[],                                     # no tools = no exfil
    )
    raw = sub_agent.run(sub_state).output
    try:
        return parse_into_schema(raw, EXTRACTION_SCHEMA)
    except SchemaError as e:
