    safe, table = redact(user_msg, tenant, run_id)
    reply = llm.generate(messages=[user(safe)])
    checked = post_check(reply.text, table, tenant)
    if isinstance(checked, Refusal): return checked
    asked = referenced_placeholders(user_msg, table)
    return re_substitute(checked, {k: v for k, v in table.items()
                                   if k in asked})

# Why this works: deterministic placeholders make the model's reasoning
# stable (the same person stays the same token); the output leak guard
# catches values the model might recite from training, which a simple
# pre-only redactor would miss.
# Related: see `input-output-guardrails`, `secrets-handling`, `session-isolation`.

# The agent's objective is a posterior, not a point estimate. Asking,
# deferring, and pausing are positive-EV moves because they sharpen the
# posterior.

reward_posterior = Posterior(initial=broad_prior_over_objectives())

function expected_utility(action):
    sampled_rewards = reward_posterior.sample(N)
    return mean(score(action, r) for r in sampled_rewards)

function value_of_information(question):
    # Ask only if the answer would narrow the posterior enough to change
    # the next action's argmax over EU.
    return expected_posterior_entropy_reduction(question)

function step(state):
    candidates = generate_candidate_actions(state)
    eus        = {a: expected_utility(a) for a in candidates}
    ask_eu     = value_of_information(best_question(state))

    if ask_eu > max(eus.values()):
        return ask_user(best_question(state))         # value-of-info wins
    return argmax(eus)

function on_feedback(signal):
    # Corrections, demonstrations, and explicit ratings all update the
    # same posterior. The trace exposes the summary so reviewers can see
    # how confident the agent is about its own objective.
    reward_posterior.update(signal)
    trace.record({posterior_summary: reward_posterior.summary()})

# Why this works: a confident agent would never defer; a preference-
# uncertain agent treats deference as rational. This is the foundation
# off-switch incentives, soft-optimisation caps, and preference inference
# build on.
# Related: see `corrigible-off-switch-incentive`, `soft-optimization-cap`, `risk-averse-reward-proxy`.

# Posterior over reward + worst-case planning in OOD: composition lets
# the agent be expected-utility in-distribution and conservative when
# it leaves the training distribution.

posterior = ObjectivePosterior(initial=broad_prior())
OOD_DETECTOR = ood_detector.load("reward_v3.design_dist")

function expected_utility(action):
    return mean(score(action, r) for r in posterior.sample(N))

function worst_case_utility(action):
    return quantile([score(action, r) for r in posterior.sample(N)],
                    q=0.10)

function pick(state, candidates):
    if OOD_DETECTOR.is_ood(state.context):
        audit.log({event: "planner.ood_switched_to_worst_case"})
        scored = {a: worst_case_utility(a) for a in candidates}
    else:
        scored = {a: expected_utility(a) for a in candidates}
    return argmax(scored)

function on_feedback(signal):
    posterior.update(signal)
    audit.log({event: "posterior.updated",
               entropy: posterior.entropy(),
               from: signal.kind})

# Why this works: the posterior captures objective uncertainty;
# risk-averse-reward-proxy uses that uncertainty to plan conservatively
# in novel contexts. Two patterns sharing one posterior produces a
# coherent 'uncertain-and-cautious' agent.
# Related: see `risk-averse-reward-proxy`, `soft-optimization-cap`, `confidence-reporting`.

# Conflict resolution is configuration, not LLM judgement. The agent
# detects the class, looks up the matrix, and implements the rule.

PRIORITY_MATRIX = {
    ("compliance",   "speed"):        "prefer_compliance",
    ("security",     "completeness"): "prefer_security_redact_remainder",
    ("cost",         "latency"):      "prefer_cost_under_50ms_budget",
    ("accuracy",     "freshness"):    "prefer_accuracy_flag_stale",
}

RESOLUTIONS = {
    "prefer_compliance":                lambda ctx: enforce_compliance(ctx),
    "prefer_security_redact_remainder": lambda ctx: redact_then_return(ctx),
    "prefer_cost_under_50ms_budget":    lambda ctx: cheap_path_if_in_budget(ctx),
    "prefer_accuracy_flag_stale":       lambda ctx: accurate_with_staleness_flag(ctx),
}

function detect_conflict(state):
    flags = []
    if state.touches_regulated_data and state.under_time_pressure:
        flags.append(("compliance", "speed"))
    if state.requires_full_disclosure and state.contains_secrets:
        flags.append(("security", "completeness"))
    return flags

function step(state):
    conflicts = detect_conflict(state)
    for c in conflicts:
        rule = PRIORITY_MATRIX.get(c)
        if rule is none:
            # Not pre-decided -- escalate, do not improvise.
            return escalate_to_human(c, state)
        audit.log({conflict: c, applied_rule: rule})
        state = RESOLUTIONS[rule](state)
    return continue_normal_processing(state)

# Why this works: LLMs lack contextual judgement to weigh competing
# objectives reliably. Pre-deciding the resolution turns a fragile
# reasoning step into a deterministic table lookup; unhandled classes
# escalate rather than improvise.
# Related: see `conflict-competency-gap`, `policy-as-code-gate`, `human-in-the-loop`.

# The priority matrix is signed config with full change history. Every
# unhandled conflict class lands in a queue with an SLA so unhandled
# cases become visible work, not silent escalations.

MATRIX_BUNDLE = config.signed_load("priority_matrix.v8")
ESCALATION_QUEUE = queue.named("conflict.unhandled", sla_hours=4)

function reload_matrix(new_bundle):
    if not config.verify_signature(new_bundle): return refused("bad_sig")
    audit.log({event: "matrix.reload",
               from: MATRIX_BUNDLE.hash, to: new_bundle.hash,
               diff: diff_matrices(MATRIX_BUNDLE.data, new_bundle.data)})
    MATRIX_BUNDLE = new_bundle

function detect_conflicts(state):
    flags = []
    for detector in CONFLICT_DETECTORS:
        if detector.fires(state): flags.append(detector.class_id)
    return flags

function resolve(state):
    conflicts = detect_conflicts(state)
    for c in conflicts:
        rule = MATRIX_BUNDLE.data.get(c)
        metrics.inc("conflict.detected." + str(c))
        if rule is none:
            metrics.inc("conflict.unhandled." + str(c))
            ticket = ESCALATION_QUEUE.put({
                conflict_class: c,
                state_summary:  state.summary,
                matrix_hash:    MATRIX_BUNDLE.hash,
                opened_at:      now(),
            })
            audit.log({event: "conflict.escalated",
                       class: c, ticket: ticket.id})
            return waiting_for_human(ticket.id)

        audit.log({event: "conflict.resolved_by_matrix",
                   class: c, rule: rule, matrix_hash: MATRIX_BUNDLE.hash})
        state = RESOLUTIONS[rule](state)
    return continue_processing(state)

# Why this works: signed config means the matrix changes ship through
# compliance review, not engineering deploys; per-class metrics tell
# the team which conflicts are new or under-specified; SLA on the
# escalation queue prevents unhandled classes from quietly piling up.
# Related: see `policy-as-code-gate`, `human-in-the-loop`, `decision-log`.

# Matrix rows are policy rules. Composition: instead of two parallel
# config surfaces (matrix and policy), the matrix lookup compiles to a
# policy query so compliance authors all rules in one place.

function conflict_query(class_id, state):
    return {
        kind:    "conflict.resolution",
        class:   class_id,
        context: {
            regulated: state.touches_regulated_data,
            time_pressure: state.under_time_pressure,
            audience: state.audience,
            secrets_present: state.contains_secrets,
        },
    }

function resolve_via_policy(state):
    conflicts = detect_conflicts(state)
    for c in conflicts:
        verdict = policy_engine.decide(conflict_query(c, state),
                                       bundle=POLICY_BUNDLE)
        audit.log({event: "matrix.via_policy",
                   class: c, rule_id: verdict.rule_id,
                   policy_hash: POLICY_BUNDLE.digest})
        match verdict.decision:
            case "resolution":
                state = RESOLUTIONS[verdict.rule_name](state)
            case "escalate":
                return escalate_to_human(c, state,
                                         policy_rule=verdict.rule_id)
            case "unknown":
                # Policy itself doesn't cover this conflict class;
                # treat as unhandled and escalate.
                return escalate_to_human(c, state,
                                         policy_rule="unspecified")
    return continue_processing(state)

# Why this works: collapsing matrix and policy into one authoring
# surface means compliance ships one bundle; the agent reads from one
# decision API; auditors trace one rule pipeline.
# Related: see `policy-as-code-gate`, `human-in-the-loop`, `decision-log`.

# Lower tiers force the action into a sandbox even when the tool itself
# could call production. Promotion to tier-3 is what unwraps the sandbox,
# making 'production access' a deliberate transition rather than a default.

function dispatch_with_sandbox(agent_id, tool, op, args):
    tier = tier_store.get((agent_id, tool), TIER_NONE)
    if tier == TIER_NONE:
        return refused("TIER_INSUFFICIENT", {tool, current_tier: tier})

    if tier == TIER_READ and op != "read":
        return refused("TIER_READ_ONLY", {tool, op})

    if tier == TIER_STAGING:
        sandbox = isolation.spawn({
            network: "staging_only",
            filesystem: "ephemeral",
            env_inherit: false,
        })
        try:
            result = sandbox.execute_tool(tool, op, args)
            audit.log({event: "sandboxed_call",
                       tool, op, tier, outcome: "ok"})
            return result
        except SandboxBreach as b:
            audit.log({event: "sandbox_breach",
                       tool, op, breach: b.kind})
            # Breach demotes immediately AND trips kill-switch.
            set_tier(agent_id, tool, TIER_NONE,
                     reason="sandbox_breach", actor="system")
            kill_switch.trip("tier_sandbox_breach")
            raise
        finally:
            sandbox.dispose()

    if tier == TIER_PROD:
        # Unwrapped: direct call. This is the deliberate promotion target.
        return tool.invoke(tool, op, args)

# Why this works: 'staging' isn't a tool-by-tool decision the agent or
# author has to remember; it's an automatic consequence of being below
# tier-3. The sandbox is the safety net while competency accumulates.
# Related: see `sandbox-isolation`, `tool-loadout-hotswap`, `kill-switch`.

K = 3
proposals = {}                                # id → {hash, count, body}

function propose_mutation(body, tick, user_approved=false):
    h = sha256(canonical(body))
    p = proposals.setdefault(h, {hash: h, count: 0, body: body,
                                  first_tick: tick})
    p.count += 1

    if user_approved or p.count >= K:
        commit(body)                          # land it
        del proposals[h]
        return "applied"
    return f"pending ({p.count}/{K})"

function tick(state):
    body = agent.next_mutation(state)         # may be None
    if body is None:
        # No endorsement this tick → any in-flight proposals reset.
        proposals.clear()
        return
    return propose_mutation(body, state.tick_no,
                            user_approved=state.user_approved)

BUCKETS = {
    (id, "min"):  TokenBucket(capacity=60,   refill=60/60),     # per minute
    (id, "hr"):   TokenBucket(capacity=1000, refill=1000/3600),  # per hour
    (id, "day"):  TokenBucket(capacity=10000, refill=10000/86400),
}

function allow(identity, cost=1):
    for horizon in ["min", "hr", "day"]:
        b = BUCKETS[(identity, horizon)]
        if not b.try_consume(cost):
            return deny(reason=horizon + "_limit", retry_after=b.eta(cost))
    return ok()

function api_gateway(req):
    v = allow(req.identity)
    if not v.ok: return http(429, retry_after=v.retry_after)
    return forward(req)

function agent_dispatch(call, state):
    # Second check inside the agent — the same identity may also be
    # making direct calls outside the gateway.
    v = allow(state.identity, cost=call.expected_tokens)
    if not v.ok: return tool_error("rate_limited", v.retry_after)
    return TOOLS[call.name].run(call.args)

# Sliding-window in Redis with per-identity sharding; brief bursts are
# allowed once per window and attributed in the audit log so abuse is
# traceable.

COUNTER = redis_store(prefix="rl")
BURST_HEADROOM = 0.15   # 15% one-shot per window

function window_count(identity, horizon):
    key = "rl:" + identity + ":" + horizon
    now_s = now()
    COUNTER.zremrangebyscore(key, 0, now_s - HORIZON_S[horizon])
    return COUNTER.zcard(key)

function allow(identity, cost=1):
    for horizon, limit in [("min", 60), ("hr", 1000), ("day", 10_000)]:
        c = window_count(identity, horizon)
        if c + cost > limit:
            burst_limit = int(limit * (1 + BURST_HEADROOM))
            if c + cost <= burst_limit and not burst_used_this_window(
                    identity, horizon):
                mark_burst_used(identity, horizon)
                audit.log({event: "rl.burst_used",
                           identity, horizon, c, cost, limit})
                continue
            metrics.inc("rl.deny." + horizon)
            return deny(reason=horizon + "_limit",
                        retry_after=horizon_reset_in(horizon))
    # Record after all horizons cleared.
    for horizon, _ in HORIZONS:
        COUNTER.zadd("rl:" + identity + ":" + horizon,
                     {uuid(): now()})
    metrics.inc("rl.allow")
    return ok()

function api_gateway(req):
    v = allow(req.identity)
    if not v.ok:
        return http(429, headers={"Retry-After": str(v.retry_after)},
                    body={code: v.reason})
    return forward(req)

function agent_dispatch(call, state):
    v = allow(state.identity, cost=call.expected_tokens)
    if not v.ok:
        return tool_error("RATE_LIMITED", retry_after=v.retry_after,
                          horizon=v.reason)
    return TOOLS[call.name].run(call.args)

# Why this works: sliding windows avoid the bursty-boundary problem of
# token-buckets at the second mark; one-shot burst headroom keeps legit
# spikes from triggering false positives; per-burst audit attribution
# means abuse can be reconstructed from logs alone.
# Related: see `circuit-breaker`, `cost-gating`, `agent-middleware-chain`.

# Rate-limit denials feed a circuit breaker. Once tripped, the agent
# stops calling the throttled tool entirely until the breaker cools,
# preventing retry storms from eating budget.

breakers = {}

function breaker_for(tool):
    if tool not in breakers:
        breakers[tool] = circuit_breaker.new(
            failure_threshold=10, window_seconds=60, cooldown_seconds=300)
    return breakers[tool]

function dispatch_with_breaker(call, state):
    cb = breaker_for(call.name)
    if cb.is_open():
        return tool_error("CIRCUIT_OPEN",
                          detail=call.name + " sidelined until " +
                                 cb.cooldown_remaining_human(),
                          hint="choose a different approach")

    v = allow(state.identity, cost=call.expected_tokens)
    if not v.ok:
        cb.record_failure("rate_limit")           # contribute to trip
        return tool_error("RATE_LIMITED",
                          retry_after=v.retry_after,
                          horizon=v.reason,
                          breaker_state=cb.state())

    try:
        result = TOOLS[call.name].run(call.args)
        cb.record_success()
        return ok(result)
    except Error as e:
        cb.record_failure("call_failed")
        raise

# Why this works: rate limiting fairly bounds use; the breaker fires
# when fairness clashes with retries, so the agent can't burn a session's
# entire token budget hammering one throttled tool. The two patterns
# defend different scales (per-call vs per-failure-streak).
# Related: see `circuit-breaker`, `cost-gating`, `kill-switch`.

TRIGGERS = [
    {name: "out_of_scope",   detect: not_in_scope},
    {name: "capability_gap", detect: needs_missing_tool},
    {name: "regulatory",     detect: violates_regulation},
    {name: "policy",         detect: violates_charter},
]

function maybe_refuse(req, state):
    for t in TRIGGERS:
        if t.detect(req, state):
            refusal = {
                kind: "refusal",
                boundary: t.name,
                reason: explain(t, req),
                alternative: suggest_alternative(t, req),
            }
            audit_log.append({req_hash: sha256(req), refusal})
            return refusal
    return null

function run_turn(req, state):
    r = maybe_refuse(req, state)
    if r:
        return reply(
            "I can't help with that here (" + r.boundary + "): " + r.reason +
            ". You might try: " + r.alternative + ".")
    return agent_reply(req, state)

# Refusal triggers aren't a parallel list -- they're parsed from the
# charter the agent already reads each turn. One source of truth for
# both behaviour and refusals.

CHARTER_PATH = "/etc/agent/charter.md"

function load_charter_triggers():
    body = read_file(CHARTER_PATH)
    return [{name: c.id, code: c.refusal_code, detect: c.detector_fn}
            for c in parse_charter_clauses(body)
            if c.is_refusal_clause]

TRIGGERS = load_charter_triggers()         # reloaded with charter changes

function maybe_refuse(req, state):
    for t in TRIGGERS:
        if t.detect(req, state):
            return {kind: "refusal",
                    boundary: t.name,
                    code: t.code,
                    charter_clause: t.name,
                    reason: "violates charter clause " + t.name}
    return none

function run_turn(req, state):
    refusal = maybe_refuse(req, state)
    if refusal:
        audit.log({event: "refusal", clause: refusal.charter_clause})
        return reply(
            "I'm declining (charter clause " + refusal.charter_clause +
            "): " + refusal.reason +
            ". You can read the clause at /charter#" +
            refusal.charter_clause + ".")
    # Charter is still loaded into the prompt; refusal is the boundary,
    # charter is the live rule set.
    return llm.generate(
        messages=[system("CHARTER:\n" + read_file(CHARTER_PATH))] +
                 state.history,
        tools=TOOLS)

# Why this works: refusal triggers and behavioural rules don't drift
# because they come from the same charter file. When compliance updates
# the charter, the agent's refusal list updates with it.
# Related: see `constitutional-charter`, `policy-as-code-gate`, `typed-refusal-codes`.

# When out of the reward's design distribution, treat the proxy as a
# noisy observation about the true reward and plan risk-averse over a
# set of plausible true rewards.

designed_reward = load("reward_v3")
design_distribution_summary = load("reward_v3.design_distribution")

function in_design_distribution(context):
    return distance(context, design_distribution_summary) < THRESHOLD

function plausible_true_rewards(proxy, context):
    # Inverse Reward Design: many true rewards could have produced this
    # proxy under the design distribution. Return a representative set.
    return ird.sample_consistent_rewards(
        proxy=proxy, design_dist=design_distribution_summary, k=64)

function score(action, reward_set):
    return [reward.evaluate(action) for reward in reward_set]

function pick_action(candidates, context):
    if in_design_distribution(context):
        # Normal case: optimise the designed proxy.
        return argmax(candidates, key=lambda a: designed_reward.evaluate(a))

    # Novel context: plan risk-averse over plausible true rewards.
    reward_set = plausible_true_rewards(designed_reward, context)
    def conservative_score(a):
        scores = score(a, reward_set)
        return quantile(scores, q=0.1)              # low-quantile = worst-case-ish
    audit.log({ood: true, reward_set_size: len(reward_set)})
    return argmax(candidates, key=conservative_score)

# Why this works: the agent stops trusting its literal reward as a
# universal target. In novel contexts it prefers actions that score
# acceptably across many plausible true objectives, which directly
# mitigates Goodhart-style specification gaming.
# Related: see `preference-uncertain-agent`, `soft-optimization-cap`, `reward-hacking`.

# OOD score is telemetry; reward-set sampling is cached for the same
# context; if worst-case and expected diverge sharply, the agent defers
# rather than guess.

ood_detector = ood.load("reward_v3.design_dist")
reward_cache = lru_cache(capacity=512)
DIVERGENCE_DEFER_THRESHOLD = 0.4

function reward_set_for(context):
    key = context_key(context)
    if key in reward_cache: return reward_cache.get(key)
    rs = ird.sample_consistent_rewards(
        proxy=designed_reward,
        design_dist=ood_detector.design_dist,
        k=64)
    reward_cache.put(key, rs)
    return rs

function expected_score(action, reward_set):
    return mean([r.evaluate(action) for r in reward_set])

function worst_case_score(action, reward_set):
    return quantile([r.evaluate(action) for r in reward_set], q=0.1)

function pick_action(candidates, context, state):
    ood_score = ood_detector.score(context)
    metrics.gauge("ood.score", ood_score)

    if ood_score < THRESHOLD:
        # Normal case: optimise the designed proxy.
        return argmax(candidates,
                      key=lambda a: designed_reward.evaluate(a))

    rs = reward_set_for(context)
    audit.log({event: "ood.engaged", ood_score,
               reward_set_size: len(rs)})

    exp = {a: expected_score(a, rs) for a in candidates}
    wcs = {a: worst_case_score(a, rs) for a in candidates}

    best_exp = max(exp.values())
    best_wcs = max(wcs.values())
    if best_exp - best_wcs > DIVERGENCE_DEFER_THRESHOLD:
        audit.log({event: "ood.deferred",
                   exp_vs_wcs: best_exp - best_wcs})
        return defer_to_user(reason="OOD_HIGH_DIVERGENCE",
                             candidates=candidates,
                             exp_scores=exp,
                             worst_case_scores=wcs)
    return argmax(candidates, key=lambda a: wcs[a])

# Why this works: detection telemetry makes the OOD pivot visible to
# operators; the deferral path acknowledges that when expected and worst-
# case disagree sharply, the agent's whole inferred objective is suspect
# and a human is the right tiebreaker.
# Related: see `preference-uncertain-agent`, `soft-optimization-cap`, `confidence-reporting`.

SECRET_REFS = {                                # outside model context
    "github_token_for_user_42": load_from_vault("gh/u42"),
    "stripe_key_live":          load_from_vault("stripe/live"),
}
SECRET_SIGNATURES = [r"ghp_[A-Za-z0-9]{36,}", r"sk_live_[A-Za-z0-9]{24,}"]

function guard_payload(p):
    blob = json_dump(p)
    for sig in SECRET_SIGNATURES:
        if regex(sig).search(blob):
            raise SecretLeak()

function call_tool(call):
    guard_payload(call.args)                  # reject literal secrets in args
    args = deepcopy(call.args)
    if "auth" in args:
        ref = args["auth"]
        args["auth"] = SECRET_REFS[ref]       # resolve outside model context
    return TOOLS[call.name].run(args)

function log_event(evt):
    redacted = scrub(evt, SECRET_REFS.values())
    trace_store.write(redacted)               # provenance ledger is clean

# Composition with MCP: tool servers register a refs-only contract; the
# MCP runtime resolves refs server-side via a vault adapter; the model
# only ever sees refs, even in transport.

MCP_TOOLS = mcp.registry()
VAULT_ADAPTER = mcp_extensions.vault_resolver("vault.internal")

function register_tool(tool_id, schema_with_refs):
    # Schema declares which args are refs (e.g. {auth: {ref: true}})
    MCP_TOOLS.register(tool_id, schema_with_refs)
    MCP_TOOLS.attach_extension(tool_id, VAULT_ADAPTER)

function agent_emit_call(call):
    # Agent emits ONLY ref strings for any arg marked ref:true.
    schema = MCP_TOOLS.schema(call.name)
    for arg_name, arg_spec in schema.args.items():
        if arg_spec.ref and not is_ref_shaped(call.args[arg_name]):
            return refused("NON_REF_FOR_REF_ARG",
                           tool: call.name, arg: arg_name)
    return mcp.client.invoke(call.name, call.args)

function mcp_server_dispatch(tool_id, args):
    schema = MCP_TOOLS.schema(tool_id)
    resolved = {}
    for k, v in args.items():
        if schema.args[k].ref:
            resolved[k] = VAULT_ADAPTER.resolve(
                v, scope=tool_id, ttl_seconds=180)
            audit.log({event: "mcp.vault_resolved",
                       tool: tool_id, ref: v,
                       scope: tool_id})
        else:
            resolved[k] = v
    return MCP_TOOLS.impl(tool_id).run(resolved)

# Why this works: MCP is the cross-process protocol; refs-only is the
# discipline that keeps secrets out of every layer the model touches.
# Composing them means even tool servers in other languages or processes
# inherit the same secrets discipline by default.
# Related: see `mcp`, `session-isolation`, `input-output-guardrails`.

IRREVERSIBLE = {"db_write", "send_email", "kubectl_delete", "wire_transfer"}

function call_tool(tool_name, args, state):
    if tool_name not in IRREVERSIBLE:
        return TOOLS[tool_name].run(args)            # cheap surfaces bypass

    sim = SIMULATORS.get(tool_name)
    if sim is None:
        # No faithful sim: degrade to HITL rather than skip the gate.
        return require_human(tool_name, args,
                             reason="no_simulator_available")

    sim_result = sim.run(args)                       # dry-run / sandbox / twin
    delta = compute_delta(sim_result, baseline=current_state())
    verdict = verifier.check(tool_name, args, delta, state.policy)

    audit_log.append({
        tool: tool_name, args: args, delta: delta, verdict: verdict,
    })

    match verdict.decision:
        case "pass":
            real = TOOLS[tool_name].run(args)
            drift_monitor.compare(predicted=delta, actual=real)
            return real
        case "ambiguous":
            return require_human(tool_name, args, delta=delta)
        case "fail":
            return tool_error("simulate_before_actuate_rejected",
                              reason=verdict.reason)

from typing import TypedDict
from langgraph.graph import StateGraph, START, END
from langgraph.checkpoint.memory import InMemorySaver
from langgraph.types import interrupt, Command


class S(TypedDict):
    action: dict
    delta: dict | None
    verdict: str | None
    result: str | None


def propose(state: S) -> S:
    # The agent (or upstream node) has chosen an irreversible action.
    return {"action": state["action"]}


def simulate(state: S) -> S:
    # Dry-run / digital twin / transactional sandbox returns the delta.
    delta = dry_run(state["action"])
    return {"delta": delta}


def verify(state: S) -> S:
    # Automated invariants first: budget, scope, allow-list, blast radius.
    v = invariant_check(state["action"], state["delta"])
    return {"verdict": v}            # 'pass' | 'fail' | 'ambiguous'


def approve_or_reject(state: S) -> S:
    if state["verdict"] == "pass":
        return {}
    if state["verdict"] == "fail":
        return {"result": f"rejected by verifier; delta={state['delta']}"}
    decision = interrupt({"approve?": state["action"], "delta": state["delta"]})
    return {"verdict": "pass" if decision == "approve" else "fail",
            "result": None if decision == "approve" else "rejected by human"}


def actuate(state: S) -> S:
    if state["verdict"] != "pass" or state["result"] is not None:
        return {}
    return {"result": run_for_real(state["action"])}


g = StateGraph(S)
for name, fn in [("propose", propose), ("simulate", simulate),
                 ("verify", verify), ("approve", approve_or_reject),
                 ("actuate", actuate)]:
    g.add_node(name, fn)
g.add_edge(START, "propose")
g.add_edge("propose", "simulate")
g.add_edge("simulate", "verify")
g.add_edge("verify", "approve")
g.add_edge("approve", "actuate")
g.add_edge("actuate", END)
app = g.compile(checkpointer=InMemorySaver())

cfg = {"configurable": {"thread_id": "sim-1"}}
first = app.invoke({"action": {"tool": "kubectl_delete",
                                "target": "app-prod-7d3"},
                    "delta": None, "verdict": None, "result": None},
                   config=cfg)
# If ambiguous, first['__interrupt__'] surfaces to the reviewer UI.
final = app.invoke(Command(resume="approve"), config=cfg)
print(final["result"])

import asyncio
from claude_agent_sdk import ClaudeAgentOptions, ResultMessage, query
