IRREVERSIBLE = {"wire_transfer", "prod_db_write", "deploy_prod", "send_email"}

SIMULATORS = {
    "prod_db_write":  db_dry_run,
    "wire_transfer": payments_digital_twin,
    "deploy_prod":   deploy_to_replica,
    "send_email":    render_only_no_smtp,
