function simulate(action):
    sim = SIMULATORS[action.name]
    return sim(action.args)                          # returns projected delta

function verify(action, projected):
    rule = INVARIANTS.get(action.name)
    if rule is none:
        return human_in_the_loop(action, projected)  # no encodable invariant
    verdict = rule(action.args, projected)
    if verdict.ok: return {decision: "accept"}
    return human_in_the_loop(action, projected, reason=verdict.reason)

function guarded_invoke(action):
    if action.name not in IRREVERSIBLE:
        return tool.invoke(action)

    if action.name not in SIMULATORS:
        return human_in_the_loop(action, projected=none,
                                  reason="no_simulator_refuse_auto")

    projected = simulate(action)
    verdict   = verify(action, projected)
    audit.log({action, projected, verdict})
    if verdict.decision != "accept":
        return refused("simulation_verify_rejected", verdict)
    return tool.invoke(action)                       # real commit

# Why this works: the projected end-state is computed and checked before
# the live commit fires, so destructive mistakes are caught while still
# reversible. HITL is reserved for cases where invariants can't be encoded.
# Related: see `human-in-the-loop`, `world-model-as-tool`, `approval-queue`, `compensating-action`.

# Replace argmax with sampling from the top q-quantile of a base
# distribution. Avoids the degenerate tail where the proxy and true
# preference diverge most.

Q = 0.05                                            # top 5% quantile
SATISFICE = 0.85                                    # 'good enough' threshold

function quantilizer_choose(candidates, base_dist, inferred_reward):
    scored = [(a, inferred_reward.evaluate(a), base_dist.prob(a))
              for a in candidates]
    cutoff = quantile([s for (_, s, _) in scored], q=1 - Q)
    top    = [(a, s, p) for (a, s, p) in scored if s >= cutoff]
    # Sample from the top q-quantile weighted by the BASE distribution,
    # not by reward. Taylor's bound: expected cost under any bounded
    # utility is at most 1/Q times the base distribution's cost.
    return weighted_sample(top, weights=[p for (_, _, p) in top])

function satisficing_choose(candidates, inferred_reward):
    for a in candidates:                            # in agent's natural order
        if inferred_reward.evaluate(a) >= SATISFICE:
            return a                                # first good-enough wins
    return argmax(candidates, key=inferred_reward.evaluate)

function pick_action(state):
    candidates = generate_candidate_actions(state)
    if state.mode == "quantilize":
        return quantilizer_choose(candidates, base_dist=state.prior,
                                  inferred_reward=state.reward)
    return satisficing_choose(candidates, inferred_reward=state.reward)

# Why this works: degenerate maxima live in the extreme tail of action
# space. Sampling the top quantile (or satisficing) leaves headroom for
# human correction and avoids the worst specification-gaming failures,
# trading a little expected score for a lot of safety.
# Related: see `preference-uncertain-agent`, `risk-averse-reward-proxy`, `corrigible-off-switch-incentive`.

