function stop_hook(state):
    if state.target_reached:
        return "stop-success"
    if state.step >= MAX_STEPS:
        return "stop-failure:budget"
    if state.last_error and not state.last_error.recoverable:
        return "stop-failure:error"
    # Stagnation: no progress across the last N steps.
    if no_progress(state, window=4):
        return "stop-failure:stagnation"
    return "continue"

function run(state):
    while true:
        state = step(state)
        verdict = stop_hook(state)
        if verdict.startswith("stop"):
            return finalize(state, verdict)

# Verdicts are structured objects, not strings; per-condition counters
# surface which condition is doing the work; slow-tick detection catches
# stuck steps; partial results are surfaced on any stop-failure.

class Verdict:
    kind: str           # "continue" | "stop-success" | "stop-failure"
    reason: str         # specific condition name
    detail: dict        # numeric thresholds, last error etc

MAX_STEPS         = 200
MAX_STEP_SECONDS  = 60
STAGNATION_WINDOW = 4

function stop_hook(state):
    metrics.gauge("hook.steps", state.step)
    if state.target_reached:
        return Verdict("stop-success", "target_reached",
                       {hit_at_step: state.step})
    if state.step >= MAX_STEPS:
        metrics.inc("hook.budget_exhausted")
        return Verdict("stop-failure", "budget",
                       {max_steps: MAX_STEPS, last_partial: state.partial})
    if state.last_step_seconds > MAX_STEP_SECONDS:
        metrics.inc("hook.slow_tick")
        return Verdict("stop-failure", "slow_tick",
                       {last_step_seconds: state.last_step_seconds,
                        last_partial: state.partial})
    if state.last_error and not state.last_error.recoverable:
        metrics.inc("hook.fatal_error")
        return Verdict("stop-failure", "error",
                       {error: state.last_error, last_partial: state.partial})
    if no_progress(state, window=STAGNATION_WINDOW):
        metrics.inc("hook.stagnation")
        return Verdict("stop-failure", "stagnation",
                       {window: STAGNATION_WINDOW,
                        last_partial: state.partial})
    return Verdict("continue", none, {})

function run(state):
    while true:
        t0 = now()
        state = step(state)
        state.last_step_seconds = now() - t0
        v = stop_hook(state)
        audit.log({event: "hook.verdict",
                   kind: v.kind, reason: v.reason, step: state.step})
        if v.kind != "continue":
            return finalize(state, v)

function finalize(state, verdict):
    state.terminated_by = verdict
    if verdict.kind == "stop-failure":
        # Surface whatever partial result we have so the user isn't
        # left with nothing.
        return {ok: false, verdict, partial: state.partial}
    return {ok: true, result: state.result}

# Why this works: structured verdicts make terminations machine-triagible;
# per-condition counters let you see which leaf does the work; emitting
# partial results on failure means the user always gets something back.
# Related: see `step-budget`, `kill-switch`, `composable-termination-conditions`.

# The stop-hook is the runtime entry point; the composable-termination-
# conditions are the implementations behind it. The hook becomes a thin
# adapter over the composite.

TERMINATION = Any([
    MaxStepsLeaf(200),
    TokenBudgetLeaf(200_000),
    StagnationLeaf(window=4),
    ExternalSignalLeaf(),
    SuccessLeaf(predicate=lambda s: s.target_reached),
])

function stop_hook(state):
    tripped, reason = TERMINATION.is_terminated(state)
    if not tripped: return ("continue", none)
    # Map composite reasons to the hook's success/failure dichotomy.
    if reason.startswith("success:"):
        return ("stop-success", reason)
    return ("stop-failure", reason)

function run(state):
    while true:
        state = step(state)
        verdict, reason = stop_hook(state)
        audit.log({event: "hook.consulted",
                   verdict, reason, step: state.step})
        if verdict != "continue":
            return finalize(state, verdict, reason)

function finalize(state, verdict, reason):
    state.terminated_by = {verdict, reason,
                           composite_hash: hash_of(TERMINATION)}
    return state

# Why this works: the hook is one named API the orchestrator calls; the
# composite behind it is what changes when termination policy evolves.
# Adding a new stop condition needs zero loop edits.
# Related: see `composable-termination-conditions`, `step-budget`, `kill-switch`.

# A Gate co-located with the Supervisor turns every hand-off into a
# checkpoint. Only accepted outputs reach side-effects.

class Gate:
    function check(sub_output, context):
        if not schema.validate(sub_output, context.expected_schema):
            return {verdict: "reject", reason: "schema", code: "SCHEMA_INVALID"}
        verdict = policy.check(sub_output, context.policy_bundle)
        if not verdict.ok:
            return {verdict: "reject", reason: "policy", code: verdict.rule_id}
        if context.allow_list and sub_output.target not in context.allow_list:
            return {verdict: "reject", reason: "allow_list", code: "NOT_ALLOWED"}
        if requires_human_review(sub_output, context):
            return {verdict: "escalate", reason: "threshold"}
        return {verdict: "accept"}

function supervisor_hop(sub_agent, task, context):
    sub_output = sub_agent.run(task)
    gate_verdict = Gate.check(sub_output, context)
    audit.log({sub_agent: sub_agent.id, gate_verdict})

    match gate_verdict.verdict:
        case "accept":
            return commit_side_effect(sub_output)
        case "reject":
            # Structured rejection, surfaced to retry-or-replan logic.
            return structured_error(code=gate_verdict.code,
                                    reason=gate_verdict.reason)
        case "escalate":
            return reviewer_queue.put(sub_output, context)

# Why this works: the Gate is deterministic and runs between 'sub-agent
# produced an output' and 'effect committed'. Policy violations cannot
# slip through on the Supervisor's authority because the Gate has hard
# reject semantics, not a best-effort fallback.
# Related: see `supervisor`, `policy-as-code-gate`, `typed-refusal-codes`, `input-output-guardrails`.

# Gate rejects flow through the typed-refusal-codes formatter so the
# Supervisor's reject signal looks identical to refusals from other
# guard surfaces. One wire format end to end.

class GateResult:
    kind: str; code: ReasonCode; detail: str; sub_output: any

function gate_check(sub_output, ctx):
    if not schema.validate(sub_output, ctx.expected_schema):
        return GateResult("reject", ReasonCode.SCHEMA_INVALID,
                          "schema mismatch", sub_output)
    pv = policy.check(sub_output, ctx.policy_bundle)
    if not pv.ok:
        return GateResult("reject", ReasonCode.POLICY_VIOLATION,
                          "rule " + pv.rule_id, sub_output)
    if ctx.allow_list and sub_output.target not in ctx.allow_list:
        return GateResult("reject", ReasonCode.UNVERIFIED_TOOL,
                          "target " + sub_output.target + " not allow-listed",
                          sub_output)
    if requires_human_review(sub_output, ctx):
        return GateResult("escalate", ReasonCode.POLICY_VIOLATION,
                          "requires_review", sub_output)
    return GateResult("accept", none, "", sub_output)

function supervisor_hop(sub_agent, task, ctx):
    sub_output = sub_agent.run(task)
    r = gate_check(sub_output, ctx)
    audit.log({event: "gate." + r.kind, code: r.code})

    match r.kind:
        case "accept":
            return commit_side_effect(r.sub_output)
        case "reject":
            # Same formatter every other refusal uses.
            return format_refusal(r.code, r.detail)
        case "escalate":
            return reviewer_queue.put(r.sub_output, ctx)

# Why this works: rejecting from the Gate produces the same wire shape
# as rejecting from input guards or policy engines, so dashboards/alerts/
# fine-tune negatives all use one parser, not three.
# Related: see `typed-refusal-codes`, `policy-as-code-gate`, `input-output-guardrails`.

# Before any side-effect step, the agent renders its full plan for
# explicit user confirmation. Recordings persist for async review.

function has_side_effects(plan):
    return any(step.tool in MUTATING_TOOLS for step in plan.steps)

function render_plan_for_human(plan):
    return {
        summary:  llm.summarise(plan, audience="non_technical"),
        steps:    [{step_no: i,
                    tool: s.tool,
                    intent: s.intent,
                    args_preview: redact_sensitive(s.args)}
                   for i, s in enumerate(plan.steps)],
        diff:     projected_diff(plan),
        plan_id:  plan.id,
    }

function run(user_goal):
    plan = planner.generate(user_goal)
    if not has_side_effects(plan):
        return executor.run(plan)                    # read-only path

    rendered = render_plan_for_human(plan)
    confirmation = await_user_confirmation(rendered) # blocking, signed action
    if confirmation.kind != "approve":
        audit.log({plan_id: plan.id, decision: confirmation})
        return refused(confirmation.reason)

    recording = recorder.start(plan.id)              # full operation recording
    try:
        result = executor.run(plan)
    finally:
        recorder.finalise(recording, visible_to_user=true)
    return result

# Why this works: the user verifies the agent understood the request
# BEFORE damage is possible. Post-hoc recordings cover the audit story
# without requiring the user to babysit each step.
# Related: see `human-in-the-loop`, `dry-run-harness`, `approval-queue`, `decision-log`.

# Plan envelope is signed and durable; user confirmation is signed; the
# user can partially approve. Recording streams to a per-user audit feed.

function render_plan(plan):
    return {
        plan_id:  plan.id,
        plan_hash: sha256(canonical(plan)),
        summary:  llm.summarise(plan, audience="non_technical"),
        steps:    [{i, tool: s.tool, intent: s.intent,
                    args_preview: redact(s.args),
                    side_effects: s.has_side_effects}
                   for i, s in enumerate(plan.steps)],
        diff:     projected_diff(plan),
    }

function await_confirmation_signed(rendered, user_id):
    sig_request = ui.request_signed_confirmation(rendered, user_id,
                                                  timeout=hours(1))
    decision = sig_request.await()
    if not verify_user_signature(decision, user_id):
        return {kind: "reject", reason: "INVALID_SIGNATURE"}
    return decision

function run_with_confirmation(user_goal, user_id):
    plan = planner.generate(user_goal)
    if not has_side_effects(plan):
        return executor.run(plan)

    plan_envelope = sign(render_plan(plan))
    plan_store.put(plan.id, plan_envelope)
    decision = await_confirmation_signed(plan_envelope, user_id)

    audit.log({event: "plan.decision",
               plan_id: plan.id, kind: decision.kind,
               approved_steps: decision.approved_steps or []})

    if decision.kind == "reject": return refused(decision.reason)
    if decision.kind == "approve_partial":
        plan = plan.subset(decision.approved_steps)

    recording_id = recorder.start(plan.id, stream_to=user_id)
    try:
        return executor.run(plan,
                            idempotency_key=plan.id + ":" +
                                            decision.signature_hash)
    finally:
        recorder.finalise(recording_id, visible_to_user=true)

# Why this works: signed confirmation prevents 'who actually approved
# this' disputes; partial approval is a real path users want; per-user
# streaming recording means the audit story is built into the UX, not
# a separate compliance afterthought.
# Related: see `human-in-the-loop`, `dry-run-harness`, `policy-gated-agent-action`.

type ToolResult = {
