function handle_followup(prev_result, proposed_call, user_intent):
    if prev_result.trust == "high":
        return TOOLS[proposed_call.name].run(proposed_call.args)
    # Low/medium trust: revalidate the proposed call against user intent.
    if not intent_check(proposed_call, user_intent):
        return refuse("tool-output-driven action not aligned with intent")
    return TOOLS[proposed_call.name].run(proposed_call.args)

# Trust labels come from a signed tool registry; instruction stripping
# is metricked per-pattern; intent checks are bounded so they can't
# become a slow path under attack.

type ToolResult = {
    envelope_version: "v3",
    tool: str,
    trust: "low"|"medium"|"high",
    content_type: str,
    body: any,
    fetched_at: timestamp,
    fingerprint: str,
}

TRUST_REGISTRY = registry.signed_load("tools.trust.v17")

INSTRUCTION_PATTERNS = [
    (r"^\s*(ignore|disregard) (all )?previous", "ignore_previous"),
    (r"^\s*you are now",                         "you_are_now"),
    (r"^\s*system:",                              "system_prefix"),
    (r"^\s*<\|im_start\|>",                       "chat_marker"),
]

function trust_for(tool_name):
    return TRUST_REGISTRY.get(tool_name, default="low")

function strip_instructions(text):
    out = []; dropped = []
    for line in text.splitlines():
        match = none
        for (pat, label) in INSTRUCTION_PATTERNS:
            if regex(pat, IGNORECASE).match(line):
                match = label; break
        if match:
            dropped.append(match)
            metrics.inc("tool.poison_strip." + match)
        else:
            out.append(line)
    return ("\n".join(out), dropped)

function sanitise(result):
    if result.trust == "low" and result.content_type.startswith("text/"):
        cleaned, dropped = strip_instructions(result.body)
        result.body = cleaned
        if dropped:
            audit.log({event: "tool.poison_stripped",
                       tool: result.tool, dropped_patterns: dropped,
                       fingerprint: result.fingerprint})
    return result

function handle_followup(prev_result, proposed_call, user_intent):
    if prev_result.trust == "high":
        return TOOLS[proposed_call.name].run(proposed_call.args)
    with timeout(200):    # intent check is bounded
        aligned = intent_service.check(proposed_call, user_intent)
    if not aligned:
        metrics.inc("tool.followup_blocked")
        audit.log({event: "tool.followup_blocked",
                   from: prev_result.tool,
                   proposed: proposed_call.name,
                   intent_hash: sha256(user_intent)})
        return refused("FOLLOWUP_NOT_ALIGNED_WITH_INTENT")
    return TOOLS[proposed_call.name].run(proposed_call.args)

# Why this works: signed trust registry stops a malicious deployer from
# silently re-labelling a tool as high-trust; per-pattern strip metrics
# surface attacker probing; bounded intent checks prevent the gate from
# becoming an attack vector itself.
# Related: see `prompt-injection-defense`, `input-output-guardrails`, `lethal-trifecta-threat-model`.

# Single source of truth. ONE place. Every guard imports from here.

enum ReasonCode:
    POLICY_VIOLATION
    RATE_LIMIT
    UNVERIFIED_TOOL
    RCE_RISK
    LOOP_DETECTED
    INTEGRITY_FAILURE
    CONTEXT_INJECTION
    OUT_OF_SCOPE
    CAPABILITY_GAP
    # ... extend over time; never rename in place.

KNOWN_CODES = set(ReasonCode)

# Legacy substrings that pre-date the enum keep parsing.
LEGACY_ALIASES = {
    "cannot comply":        ReasonCode.POLICY_VIOLATION,
    "blocked by policy":    ReasonCode.POLICY_VIOLATION,
    "unsupported tool":     ReasonCode.UNVERIFIED_TOOL,
    "too many requests":    ReasonCode.RATE_LIMIT,
}

function format_refusal(code: ReasonCode, detail: str) -> str:
    assert code in KNOWN_CODES
    return "REFUSED: " + code.name + ": " + detail

function parse_refusal(s: str) -> (ReasonCode, str) | None:
    if s.startswith("REFUSED: "):
        rest = s[len("REFUSED: "):]
        name, _, detail = rest.partition(": ")
        code = ReasonCode.lookup(name)            # None if unknown
        if code is not None:
            return (code, detail)
        return None                                # unknown code -> parse miss
    for needle, code in LEGACY_ALIASES.items():
        if needle in s.lower():
            return (code, s)                      # legacy substring still parses
    return None

# Every guard surface uses format_refusal exclusively.
function tool_loop_guard(call, state):
    if call.name not in state.allowed_tools:
        return format_refusal(ReasonCode.UNVERIFIED_TOOL,
                              "tool '" + call.name + "' not in agent's allow-list")
    if called_too_often(call, state):
        return format_refusal(ReasonCode.LOOP_DETECTED,
                              "same tool called 7x in 12s")
    return ok()

# Downstream consumers depend ONLY on parse_refusal, never on raw strings.
function audit_event(refusal_string):
    parsed = parse_refusal(refusal_string)
    if parsed is None:
        metrics.inc("refusal.unparsed")            # signal, not a crash
        return
    code, detail = parsed
    metrics.inc("refusal." + code.name)
    if code in {ReasonCode.RCE_RISK, ReasonCode.INTEGRITY_FAILURE}:
        alert_oncall(code, detail)
